package org.apache.commons.csv;
import static org.junit.jupiter.api.Assertions.*;
import static org.mockito.Mockito.*;

import java.io.File;
import java.io.IOException;
import java.nio.charset.Charset;
import java.nio.file.Path;

import org.apache.commons.csv.CSVFormat;
import org.apache.commons.csv.CSVPrinter;
import org.junit.jupiter.api.BeforeEach;
import org.junit.jupiter.api.Test;
import org.mockito.MockedStatic;
import org.mockito.Mockito;

public class CSVFormatTest {

    private CSVFormat csvFormat;
    private Path mockPath;
    private File mockFile;

    @BeforeEach
    public void setUp() {
        csvFormat = CSVFormat.DEFAULT;
        mockPath = mock(Path.class);
        mockFile = mock(File.class);
    }

    @Test
    public void testPrint_PathAndCharset_Success() throws IOException {
        Charset charset = Charset.defaultCharset();

        when(mockPath.toFile()).thenReturn(mockFile);

        // Spy on csvFormat to mock print(File, Charset)
        CSVFormat spyFormat = Mockito.spy(csvFormat);
        CSVPrinter mockPrinter = mock(CSVPrinter.class);
        doReturn(mockPrinter).when(spyFormat).print(mockFile, charset);

        CSVPrinter result = spyFormat.print(mockPath, charset);

        assertNotNull(result);
        assertEquals(mockPrinter, result);

        verify(mockPath, times(1)).toFile();
        verify(spyFormat, times(1)).print(mockFile, charset);
    }

    @Test
    public void testPrint_PathNullCharset_ThrowsNullPointerException() {
        when(mockPath.toFile()).thenReturn(mockFile);
        assertThrows(NullPointerException.class, () -> csvFormat.print(mockPath, null));
    }

    @Test
    public void testPrint_PathNull_ThrowsNullPointerException() {
        assertThrows(NullPointerException.class, () -> csvFormat.print(null, Charset.defaultCharset()));
    }

}
